body.script:
// Configuration
const width = 1200;
const height = 700;

// Geographical coordinates [lon, lat]
const locations = [
    { name: "Mozambique", coords: [32.57, -25.92], beat: 1, info: "Cultural Immersions" },
    { name: "Eswatini", coords: [31.13, -26.31], beat: 1, info: "Cultural Immersions" },
    { name: "Lesotho", coords: [27.48, -29.31], beat: 1, info: "Cultural Immersions" },
    { name: "Johannesburg", coords: [28.05, -26.20], beat: 2, info: "Solo Travel Security" },
    { name: "Zambia", coords: [28.28, -15.42], beat: 3, info: "Social Sustainable Tourism" },
    { name: "Harare", coords: [31.05, -17.83], beat: 4, info: "Social Sustainable Tourism" }
];

// Projection focused on Southern Africa
const projection = d3.geoMercator()
    .center([30, -22]) 
    .scale(1600)
    .translate([width / 2, height / 2]);

const path = d3.geoPath().projection(projection);
const svg = d3.select("#map-svg");
const worldGroup = d3.select("#map-world");
const citiesGroup = d3.select("#cities-layer");
const routePath = d3.select("#main-route");
const traveler = d3.select("#traveler");
const card = d3.select("#info-card");

async function init() {
    const worldData = await d3.json("https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json");
    const countries = topojson.feature(worldData, worldData.objects.countries).features;

    // Draw Map
    worldGroup.selectAll(".country")
        .data(countries)
        .enter().append("path")
        .attr("class", "country")
        .attr("d", path)
        .style("fill", "#1a252f");

    // Draw Graticule
    worldGroup.append("path")
        .datum(d3.geoGraticule()())
        .attr("class", "graticule")
        .attr("d", path);

    // Prepare Route
    const lineData = locations.map(d => d.coords);
    const lineGenerator = d3.line()
        .x(d => projection(d)[0])
        .y(d => projection(d)[1])
        .curve(d3.curveCatmullRom.alpha(0.5));

    const fullRoutePath = lineGenerator(lineData);
    routePath.attr("d", fullRoutePath);
    const totalLength = routePath.node().getTotalLength();
    routePath.style("stroke-dasharray", totalLength + " " + totalLength)
             .style("stroke-dashoffset", totalLength);

    // Create City Dots
    locations.forEach((loc, i) => {
        const [x, y] = projection(loc.coords);
        const group = citiesGroup.append("g")
            .attr("id", `city-${i}`)
            .attr("transform", `translate(${x},${y})`);

        group.append("circle").attr("class", "city-dot pulse").attr("r", 8);
        group.append("circle").attr("class", "city-dot").attr("r", 4);

        group.append("text")
            .attr("class", "city-label")
            .attr("id", `label-${i}`)
            .attr("text-anchor", "middle")
            .attr("y", -15)
            .text(loc.name);
    });

    startAnimation();
}

function startAnimation() {
    const totalLength = routePath.node().getTotalLength();

    // Define key timestamps (0-7s)
    const durationBeat1 = 3000; // Moz -> Eswatini -> Lesotho
    const pauseBeat2 = 1000;    // Joburg
    const durationBeat3 = 3000; // Zambia -> Harare

    // Use D3 transition for cinematic control
    function runSequence() {
        // Reset
        routePath.interrupt().style("stroke-dashoffset", totalLength);
        traveler.style("visibility", "visible").attr("transform", `translate(${projection(locations[0].coords)})`);
        d3.selectAll(".city-label").style("opacity", 0).classed("label-float", false);
        card.classed("active", false);

        const t = d3.transition().duration(7000).ease(d3.easeLinear);

        // Path and Traveler movement
        routePath.transition(t)
            .styleTween("stroke-dashoffset", function() {
                return function(pct) {
                    const currentOffset = totalLength * (1 - pct);

                    // Calculate pauses and beats
                    let displayPct = pct;
                    // Manual mapping for cinematic beats
                    if (pct < 0.42) { // 0-3s is approx 42% of 7s
                        displayPct = d3.easeCubicOut(pct / 0.42) * 0.42; 
                    } else if (pct < 0.57) { // 3-4s is pause at Joburg (approx 57%)
                        displayPct = 0.42; 
                    } else { // 4-7s
                        const subPct = (pct - 0.57) / 0.43;
                        displayPct = 0.42 + d3.easeCubicInOut(subPct) * 0.58;
                    }

                    const point = routePath.node().getPointAtLength((displayPct) * totalLength);
                    traveler.attr("transform", `translate(${point.x},${point.y})`);

                    // Check triggers for UI
                    updateTriggers(displayPct);

                    return totalLength * (1 - displayPct);
                };
            })
            .on("end", () => {
                // Zoom Finale
                const finalPoint = projection(locations[5].coords);
                svg.transition().duration(1500).ease(d3.easeCubicInOut)
                    .attr("viewBox", `${finalPoint[0]-200} ${finalPoint[1]-150} 400 300`)
                    .on("end", () => {
                        setTimeout(() => {
                            svg.transition().duration(1000).attr("viewBox", "0 0 1200 700");
                            setTimeout(runSequence, 1000);
                        }, 2000);
                    });
            });
    }

    let lastIndex = -1;
    function updateTriggers(pct) {
        // Approximate progress points for locations
        // 0: Moz, 1: Eswatini, 2: Lesotho, 3: Joburg, 4: Zambia, 5: Harare
        const thresholds = [0, 0.1, 0.25, 0.42, 0.8, 0.99];

        thresholds.forEach((th, i) => {
            if (pct >= th && lastIndex < i) {
                lastIndex = i;
                d3.select(`#label-${i}`).classed("label-float", true);

                // Card logic
                const loc = locations[i];
                if (loc) {
                    card.classed("active", true);
                    d3.select("#card-text").text(loc.info);
                    d3.select("#card-tag").text(i < 3 ? "Cultural Immersions" : (i === 3 ? "Safety Protocols" : "Sustainable Impact"));
                }
            }
        });

        if (pct < 0.01) lastIndex = -1;
    }

    runSequence();
}

init();
